const src = $input.first().json;
const body = src.body || src;

const quoteId = body.quoteId || body.quote_id || null;
const rawPhone = (body.phone || '').toString().trim();
const name = (body.name || 'Cliente').toString().trim();
const status = (body.status || '').toString().trim();
const prevStatus = (body.prevStatus || body.prev_status || '').toString().trim();
const kwp = body.kwp != null ? Number(body.kwp) : null;
const totalCop = body.totalCop || body.total_cop || null;
const trackingToken = (body.trackingToken || body.tracking_token || '').toString().trim();
const installerName = (body.installerName || body.installer_name || '').toString().trim();

if (!rawPhone) {
  return [{ json: { ok: false, reason: 'missing_phone' } }];
}
if (!status) {
  return [{ json: { ok: false, reason: 'missing_status' } }];
}
if (!quoteId) {
  return [{ json: { ok: false, reason: 'missing_quote_id' } }];
}

const digits = rawPhone.replace(/\D/g, '');
let phone = '';
if (digits.length === 10) {
  phone = '+57' + digits;
} else if (digits.startsWith('57') && digits.length === 12) {
  phone = '+' + digits;
} else if (digits.startsWith('57') && digits.length > 12) {
  phone = '+' + digits.slice(0, 12);
} else {
  return [{ json: { ok: false, reason: 'invalid_phone' } }];
}

if (!phone.startsWith('+57') || phone.length !== 13) {
  return [{ json: { ok: false, reason: 'invalid_phone' } }];
}

return [{ json: { ok: true, quoteId, phone, name, status, prevStatus, kwp, totalCop, trackingToken, installerName } }];

const norm = $input.first().json;
const { quoteId, phone, name, status, kwp, totalCop, trackingToken, installerName } = norm;

const trackingUrl = 'https://solar-hub.co/?view=seguimiento&id=' + quoteId + '&t=' + (trackingToken || '');

const kwpFormatted = kwp ? kwp.toFixed(1) + ' kWp' : 'N/D';
const totalFormatted = totalCop ? '$' + Number(totalCop).toLocaleString('es-CO') + ' COP' : 'N/D';
const installer = installerName || 'nuestro equipo';
const installerScheduled = installerName || 'nuestro instalador';

const phoneNumberId = process.env.WHATSAPP_PHONE_NUMBER_ID;
const token = process.env.WHATSAPP_ACCESS_TOKEN;
const url = 'https://graph.facebook.com/v18.0/' + phoneNumberId + '/messages';

const templateMap = {
  'nueva': { name: 'quote_received', params: [name, trackingUrl] },
  'propuesta_enviada': { name: 'quote_ready', params: [name, kwpFormatted, totalFormatted, trackingUrl] },
  'aprobada': { name: 'quote_approved', params: [name, installer] },
  'en_instalación': { name: 'installation_scheduled', params: [name, 'próximamente', installerScheduled] },
  'ganada': { name: 'installation_completed', params: [name, 'https://solar-hub.co'] }
};

const tmpl = templateMap[status];
if (!tmpl) {
  return [{ json: { ok: false, reason: 'no_template', status } }];
}

const waBody = JSON.stringify({
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: phone,
  type: 'template',
  template: {
    name: tmpl.name,
    language: { code: 'es' },
    components: [{ type: 'body', parameters: tmpl.params.map(p => ({ type: 'text', text: String(p) })) }]
  }
});

return [{ json: { ok: true, phone, template: tmpl.name, params: tmpl.params, body: waBody, url, token } }];
